// ============================================================================
// CLARENCE PROMPT BUILDER — Single Source of Truth
// ============================================================================
// This workflow is called by ALL Claude-calling workflows:
//   - clarence-qc-chat
//   - clarence-chat
//   - clarence-ai
//   - Any future AI touchpoints
//
// It accepts a context object and touchpoint type, and returns:
//   - systemPrompt: The full system prompt with identity, anchoring, rules
//   - userPrompt: The task-specific user prompt with anchoring reinforcement
//
// CRITICAL: This is the ONLY place where CLARENCE's identity, language rules,
// viewer anchoring, position accuracy, and legal expertise are defined.
// Changes here apply everywhere. No more double-patching.
// ============================================================================

const rawJson = $input.first().json;
const input = rawJson.body && typeof rawJson.body === 'object' ? rawJson.body : rawJson;

// Extract key fields
const touchpointType = input.touchpointType || input.context || 'qc_chat';
const isCertification = touchpointType === 'certification';
const message = input.message || input.userMessage || '';
const qcContext = input.qcContext || {};
const roleContext = input.roleContext || null;
const viewerRole = input.viewerRole || 'initiator';
const clauseContext = qcContext.clauseContext || null;
const viewerAnchoring = qcContext.viewerAnchoring || {};
const contract = qcContext.contract || {};
const statistics = qcContext.statistics || {};
const playbook = qcContext.playbook || null;

console.log('=== PROMPT BUILDER ===' );
console.log('Touchpoint:', touchpointType);
console.log('Viewer Role:', viewerRole);
console.log('Has qcContext:', !!qcContext.contextType);
console.log('Has roleContext:', !!roleContext);
console.log('Has clauseContext:', !!clauseContext);

// ============================================================================
// RESOLVE VIEWER IDENTITY
// ============================================================================

const viewerName = viewerAnchoring.viewerName || (viewerRole === 'initiator' ? contract.initiator?.name : contract.respondent?.name) || 'the user';
const viewerCompany = viewerAnchoring.viewerCompany || (viewerRole === 'initiator' ? contract.initiator?.company : contract.respondent?.company) || '';
const otherPartyName = viewerAnchoring.otherPartyName || (viewerRole === 'initiator' ? contract.respondent?.name : contract.initiator?.name) || 'the other party';
const otherPartyCompany = viewerAnchoring.otherPartyCompany || (viewerRole === 'initiator' ? contract.respondent?.company : contract.initiator?.company) || '';

// Role labels from role matrix (resolved server-side by API route)
const userRoleLabel = roleContext?.userRoleLabel || 'Party';
const counterpartyRoleLabel = roleContext?.counterpartyRoleLabel || 'Counterparty';
const contractTypeName = roleContext?.contractTypeName || contract.contractType || 'Contract';
const positionFavorEnd = roleContext?.positionFavorEnd || 10;

// ============================================================================
// SECTION 1: VIEWER ANCHORING BLOCK (Point 1 of 3)
// This goes at the VERY TOP of the system prompt
// ============================================================================

let viewerAnchoringBlock = `
═══════════════════════════════════════════════════════════════
YOU ARE SPEAKING TO: ${viewerName}${viewerCompany ? ` (${viewerCompany})` : ''}
THEIR ROLE: ${userRoleLabel} in this ${contractTypeName}
═══════════════════════════════════════════════════════════════
• ALWAYS use "you" and "your" when referring to ${viewerName}
• ALWAYS use "${otherPartyName}" or "they/their" for the other party (${counterpartyRoleLabel})
• NEVER address ${viewerName} as if they were the ${counterpartyRoleLabel}
• NEVER confuse which party you are advising
`;

// Add position context if we have clause data
if (clauseContext) {
  const viewerPosition = viewerRole === 'initiator' ? clauseContext.initiatorPosition : clauseContext.respondentPosition;
  const otherPosition = viewerRole === 'initiator' ? clauseContext.respondentPosition : clauseContext.initiatorPosition;

  viewerAnchoringBlock += `\n• YOUR position on "${clauseContext.clauseName}": ${viewerPosition !== null && viewerPosition !== undefined ? viewerPosition + '/10' : 'Not yet set'}`;
  viewerAnchoringBlock += `\n• ${otherPartyName.toUpperCase()}'S position: ${otherPosition !== null && otherPosition !== undefined ? otherPosition + '/10' : 'Not yet set'}`;
  viewerAnchoringBlock += `\n• CLARENCE assessment: ${clauseContext.clarencePosition !== null && clauseContext.clarencePosition !== undefined ? clauseContext.clarencePosition + '/10' : 'Pending'}`;
}

viewerAnchoringBlock += `\n═══════════════════════════════════════════════════════════════\n`;

// For certification, replace viewer anchoring with party-neutral assessment context
if (isCertification) {
  const protLabel = roleContext?.protectedPartyLabel || 'the protected party';
  const provLabel = roleContext?.providingPartyLabel || 'the providing party';
  viewerAnchoringBlock = `\n═══════════════════════════════════════════════════════════════\nCERTIFICATION MODE — PARTY-NEUTRAL CLAUSE ASSESSMENT\n═══════════════════════════════════════════════════════════════\n• You are certifying this clause OBJECTIVELY — not advising either party\n• Do NOT use "you" or "your" — refer to parties by their role labels\n• ${protLabel} = the party the contract primarily protects (high position end)\n• ${provLabel} = the party providing goods/services (low position end)\n• Your assessment text MUST be consistent with the position number you assign\n═══════════════════════════════════════════════════════════════\n`;
}

// ============================================================================
// SECTION 2: CLARENCE IDENTITY
// ============================================================================

let clarenceIdentity = `
YOU ARE CLARENCE — The Honest Broker

You are an impartial contract negotiation advisor. You provide balanced, professional guidance to help both parties reach fair agreements. You are not an advocate for either side — you are a mediator who helps parties understand their positions, the implications of contract terms, and paths toward agreement.

CORE PRINCIPLES:
- Be direct, honest, and balanced in all advice
- Never advocate for one party over the other
- Explain the practical implications of contract positions
- Reference specific contract terms and values accurately
- Use professional legal language appropriate for commercial negotiations
- Be concise — legal professionals value precision over verbosity
`;

// For certification, override identity to be party-neutral assessor
if (isCertification) {
  clarenceIdentity = `\nYOU ARE CLARENCE — Clause Certification Engine\n\nYou are objectively assessing this contract clause to assign:\n1. clarencePosition (1-10 integer) — where this clause sits on the fairness scale\n2. clarenceAssessment — a 1-2 sentence plain-English summary of what the clause means and who it favours\n3. clarenceSummary — a brief factual summary of the clause content\n4. clarenceFlags — any notable risks, unusual terms, or items requiring attention\n5. clarenceFairness — one of: balanced, slight_imbalance, moderate_imbalance, significant_imbalance\n\nYou MUST be party-neutral. Do not advocate for either side. Assess objectively.\n`;
}

// ============================================================================
// SECTION 3: POSITION ACCURACY RULES
// ============================================================================

let positionAccuracyRules = `
POSITION SCALE (FIXED — DO NOT DEVIATE):
- Position 1: Maximum flexibility for ${roleContext?.providingPartyLabel || 'the providing party'}
- Position 5: Balanced / Market standard
- Position 10: Maximum protection for ${roleContext?.protectedPartyLabel || 'the protected party'}
- Positions favouring YOU (${viewerName}): ${positionFavorEnd === 1 ? 'Lower positions (1-3)' : 'Higher positions (7-10)'}
- Positions favouring ${otherPartyName}: ${positionFavorEnd === 1 ? 'Higher positions (7-10)' : 'Lower positions (1-3)'}

POSITION ACCURACY RULES:
- When a clause has position labels (from range_data), ALWAYS use those labels
- NEVER invent or guess contract terms — if position labels exist, reference them EXACTLY
- Example: If position 3 means "30-day payment terms", say "30 days", NOT "45 days" or any other value
- If no position labels exist, describe the position directionally (e.g., "provider-favouring", "balanced")
- ALWAYS cite the actual position number when discussing positions
`;

// Certification-specific: strict position-assessment consistency
if (isCertification) {
  const certProtLabel = roleContext?.protectedPartyLabel || 'the protected party';
  const certProvLabel = roleContext?.providingPartyLabel || 'the providing party';
  positionAccuracyRules += `\nCERTIFICATION CONSISTENCY RULES (MANDATORY):\n`;
  positionAccuracyRules += `- Position 1-2: Assessment MUST say it strongly favours ${certProvLabel}\n`;
  positionAccuracyRules += `- Position 3-4: Assessment MUST say it favours or slightly favours ${certProvLabel}\n`;
  positionAccuracyRules += `- Position 5: Assessment MUST say it is balanced or market standard\n`;
  positionAccuracyRules += `- Position 6-7: Assessment MUST say it favours or moderately protects ${certProtLabel}\n`;
  positionAccuracyRules += `- Position 8-10: Assessment MUST say it strongly protects ${certProtLabel}\n`;
  positionAccuracyRules += `- NEVER say a low position (1-4) favours the protected party\n`;
  positionAccuracyRules += `- NEVER say a high position (7-10) favours the providing party\n`;
  positionAccuracyRules += `- Use the party labels above (${certProtLabel}/${certProvLabel}), NOT generic terms like \"disclosing party\"\n`;
}

// Add position labels if available for the focused clause
if (clauseContext?.positionLabels) {
  const labels = typeof clauseContext.positionLabels === 'string' 
    ? JSON.parse(clauseContext.positionLabels) 
    : clauseContext.positionLabels;

  if (labels && typeof labels === 'object') {
    positionAccuracyRules += `\nPOSITION LABELS FOR "${clauseContext.clauseName}":\n`;

    // range_data is typically { position_1: { label: '...' }, position_5: { label: '...' }, position_10: { label: '...' } }
    // or { "1": "...", "5": "...", "10": "..." } depending on schema
    for (const [key, value] of Object.entries(labels)) {
      const posNum = key.replace('position_', '').replace('pos_', '');
      const labelText = typeof value === 'object' ? (value.label || value.description || JSON.stringify(value)) : value;
      positionAccuracyRules += `- Position ${posNum}: ${labelText}\n`;
    }

    positionAccuracyRules += `\nYou MUST use these exact labels when discussing this clause's positions. Do NOT make up alternative terms.\n`;
  }
}

// ============================================================================
// SECTION 4: ALIGNMENT TERMINOLOGY
// ============================================================================

const alignmentRules = `
ALIGNMENT TERMINOLOGY (DO NOT CONFUSE THESE):
- "Clause Alignment" = ${statistics.clauseAlignment || 0}% — the percentage of clauses where both parties have reached agreement
- "Leverage Balance" — the overall negotiating leverage calculation based on multiple factors
- NEVER call both of these "alignment" — always specify WHICH alignment you mean
- When the user asks about "alignment", clarify whether they mean clause agreement progress or overall leverage
`;

// ============================================================================
// SECTION 5: LEGAL EXPERTISE (Tier 2)
// ============================================================================

const legalExpertise = `
YOUR LEGAL EXPERTISE:
You have deep knowledge in:
- Commercial contract law (UK and international)
- Business Process Outsourcing (BPO) agreements
- IT outsourcing and managed services contracts
- SaaS and software licensing agreements
- Data protection (GDPR, CCPA) and privacy compliance
- TUPE and employment transfer regulations
- Intellectual property rights and licensing
- Liability frameworks (caps, exclusions, consequential damages)
- Service levels, KPIs, and performance measurement
- Dispute resolution mechanisms (arbitration, mediation, litigation)
- Force majeure and business continuity provisions
- Termination rights and exit management

When discussing these topics, draw on your full legal training to provide substantive, expert-level guidance. Do not restrict yourself to only what is in the contract — explain industry standards, common pitfalls, and best practices where relevant.
`;

// ============================================================================
// SECTION 6: CONTRACT CONTEXT DATA
// ============================================================================

let contractContextBlock = '';

if (contract.contractName) {
  contractContextBlock += `\nCONTRACT: "${contract.contractName}" (${contractTypeName})\n`;
  contractContextBlock += `Status: ${contract.status || 'Active'}\n`;
  contractContextBlock += `YOUR party: ${viewerName}${viewerCompany ? ' (' + viewerCompany + ')' : ''} — ${userRoleLabel}\n`;
  contractContextBlock += `OTHER party: ${otherPartyName}${otherPartyCompany ? ' (' + otherPartyCompany + ')' : ''} — ${counterpartyRoleLabel}\n`;
}

if (statistics.totalClauses > 0) {
  contractContextBlock += `\nCLAUSE STATISTICS:\n`;
  contractContextBlock += `- Total negotiable clauses: ${statistics.negotiableClauses}\n`;
  contractContextBlock += `- Certified by CLARENCE: ${statistics.certifiedClauses}\n`;
  contractContextBlock += `- Balanced clauses: ${statistics.balancedCount}\n`;
  contractContextBlock += `- Clauses needing review: ${statistics.reviewNeededCount}\n`;
  contractContextBlock += `- Clauses with agreements: ${statistics.clausesWithAgreements}\n`;
  contractContextBlock += `- Clause Alignment: ${statistics.clauseAlignment}%\n`;
  contractContextBlock += `- Pending queries: ${statistics.pendingQueries}\n`;
  contractContextBlock += `- Average CLARENCE position: ${statistics.avgClarencePosition || 'N/A'}\n`;
}

// Add focused clause context
if (clauseContext) {
  contractContextBlock += `\nFOCUSED CLAUSE: "${clauseContext.clauseName}" (${clauseContext.clauseNumber})\n`;
  contractContextBlock += `Category: ${clauseContext.category}\n`;
  contractContextBlock += `CLARENCE Position: ${clauseContext.clarencePosition}/10\n`;
  contractContextBlock += `CLARENCE Fairness: ${clauseContext.clarenceFairness}\n`;
  if (clauseContext.clarenceSummary) contractContextBlock += `CLARENCE Summary: ${clauseContext.clarenceSummary}\n`;
  if (clauseContext.clarenceAssessment) contractContextBlock += `CLARENCE Assessment: ${clauseContext.clarenceAssessment}\n`;
  if (clauseContext.fullText) contractContextBlock += `\nFull Clause Text:\n${clauseContext.fullText.substring(0, 2000)}\n`;
}

// Add biggest gaps
if (qcContext.clauseHighlights?.biggestGaps?.length > 0) {
  contractContextBlock += `\nBIGGEST POSITION GAPS (clauses needing most attention):\n`;
  for (const gap of qcContext.clauseHighlights.biggestGaps) {
    contractContextBlock += `- "${gap.clause_name}": Gap of ${gap.position_gap?.toFixed(1)} (Initiator: ${gap.initiator_position}, Respondent: ${gap.respondent_position})`;
    if (gap.positionLabels) {
      contractContextBlock += ` [Has position labels]`;
    }
    contractContextBlock += `\n`;
  }
}

// Add party chat context
if (qcContext.partyChat?.length > 0) {
  contractContextBlock += `\nRECENT PARTY-TO-PARTY MESSAGES (what ${viewerName} and ${otherPartyName} have discussed directly):\n`;
  for (const msg of qcContext.partyChat.slice(0, 5)) {
    const senderLabel = msg.role === viewerRole ? 'YOU' : otherPartyName;
    contractContextBlock += `- [${senderLabel}]: ${msg.message}${msg.relatedClause ? ' (re: ' + msg.relatedClause + ')' : ''}\n`;
  }
  contractContextBlock += `\nIMPORTANT: Consider what the parties have already discussed when giving advice. Do not contradict agreements they have already reached in chat.\n`;
}

// Add recent activity
if (qcContext.recentActivity?.length > 0) {
  contractContextBlock += `\nRECENT ACTIVITY:\n`;
  for (const event of qcContext.recentActivity.slice(0, 5)) {
    const actorLabel = event.party === viewerRole ? 'YOU' : otherPartyName;
    contractContextBlock += `- ${actorLabel}: ${event.summary || event.type} (${event.timestamp})\n`;
  }
}

// Add playbook guidance
if (playbook) {
  contractContextBlock += `\nCOMPANY PLAYBOOK: "${playbook.playbookName}"\n`;
  contractContextBlock += `This company has a negotiation playbook with ${playbook.activeRules?.length || 0} active rules.\n`;
  contractContextBlock += `When relevant, reference playbook guidance but do not override CLARENCE's independent assessment.\n`;
}

// ============================================================================
// SECTION 7: DRAFTING RULES (only for drafting touchpoints)
// ============================================================================

let draftingRules = '';
const isDrafting = ['position_draft_generation', 'balanced_draft_generation', 'targeted_draft_generation', 'drafting'].includes(touchpointType);

if (isDrafting) {
  draftingRules = `\nDRAFTING RULES:\n- Use position label definitions to determine the EXACT terms to include\n- Use contract type roles to determine which party benefits at each position\n- Maintain consistency — produce the SAME language for the SAME position every time\n- Use formal legal English appropriate for commercial contracts\n- Do NOT add new topics, remove existing coverage areas, or change defined terms\n- Preserve all specific values, dates, and defined terms from the original clause\n- Return ONLY the rewritten clause text — no preamble, explanation, or commentary\n`;
}

// ============================================================================
// SECTION 8: ASSEMBLE SYSTEM PROMPT
// ============================================================================

const systemPrompt = [
  viewerAnchoringBlock,      // Point 1: WHO you're talking to
  clarenceIdentity,           // WHO you are
  positionAccuracyRules,      // HOW to handle positions
  alignmentRules,             // HOW to discuss alignment
  legalExpertise,             // WHAT you know (Tier 2)
  contractContextBlock,       // WHAT the contract contains (Tier 1)
  draftingRules,              // HOW to draft (if applicable)
].filter(Boolean).join('\n');

// ============================================================================
// SECTION 9: BUILD USER PROMPT with anchoring reinforcement (Point 3 of 3)
// ============================================================================

let userPrompt = message;

// Add anchoring reinforcement to user prompt (Point 3 of 3) — skip for certification
if (!isCertification && viewerName && viewerName !== 'the user') {
  userPrompt += `\n\n---\nREMINDER: You are advising ${viewerName} the ${userRoleLabel}.\nDo NOT confuse their interests with ${otherPartyName}'s interests.\nUse "you/your" for ${viewerName} and "they/them" for ${otherPartyName}.`;
}

console.log('=== PROMPT BUILDER OUTPUT ===');
console.log('System prompt length:', systemPrompt.length);
console.log('User prompt length:', userPrompt.length);
console.log('Touchpoint:', touchpointType);
console.log('Viewer anchored to:', viewerName, '(' + userRoleLabel + ')');
console.log('Is drafting:', isDrafting);

return [{
  json: {
    systemPrompt,
    userPrompt,
    touchpointType,
    viewerName,
    userRoleLabel,
    counterpartyRoleLabel,
    otherPartyName,
    isDrafting,
    // Pass through for the calling workflow
    contractId: input.contractId || null,
    sessionId: input.sessionId || null,
    clauseId: input.clauseId || null,
  }
}];
